#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        int **graph = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            graph[i] = (int *)malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            graph[u][v] = 1;
            graph[v][u] = 1;
        }
        long long ans = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            int count = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    if ((mask & (1 << i)) && (mask & (1 << j)) && graph[i][j]) {
                        count++;
                    }
                }
            }
            ans = (ans + (long long)count * count * count) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

